// Get the AI text
const text = $input.all()[0].json.output || $input.all()[0].json.content;

// Find the first JSON object using Regex (Safe Mode)
const match = text.match(/\{[\s\S]*?\}/);

if (match) {
    return JSON.parse(match[0]);
} else {
    return { error: "No JSON found" };
}

