// 1. Order Data from previous Code Node
const order = $('Code in JavaScript1').item.json;

// 2. Product Data from Search Node (Input to this node)
const product = $input.first().json;

// 3. Safe Numbers (Convert to number to avoid NaN)
// Agar Price/Stock empty ho to 0 maan lega
const price = parseFloat(product.Price) || 0;
const stock = parseInt(product.Stock) || 0;
const quantity = parseInt(order.Quantity) || 0;

// 4. Calculate Total
const totalAmount = price * quantity;

// 5. Return Clean Data for Next Steps
return {
  json: {
    // --- Order Details ---
    CustomerName: order.CustomerName,
    ProductSKU: order.ProductSKU,
    Quantity: quantity,
    PaymentMethod: order.PaymentMethod,

    // --- Calculated Values ---
    TotalAmount: totalAmount,

    // --- Product Details (For Updates) ---
    ProductID: product.id,       // AirTable Update ke liye
    ProductStock: stock,         // Stock Calculation ke liye
    ProductWooID: product.WooID, // WooCommerce Sync ke liye

    // --- Meta Data ---
    Date: new Date().toISOString().split('T')[0],
    Platform: "CRM (Live Sale)",
    InvoiceStatus: "Pending"
  }
};

const order = $node["Search Orders"].json;
